alter table profiles enable row level security; alter table partner_profiles enable row level security; alter table game_sessions enable row level security; alter table stage_results enable row level security; alter table saved_expressions enable row level security; alter table scenario_history enable row level security; alter table leaderboard_entries enable row level security; alter table user_badges enable row level security;
do $$ declare t text; begin foreach t in array array['profiles','partner_profiles','game_sessions','stage_results','saved_expressions','scenario_history','user_badges'] loop execute format('drop policy if exists %I_self on %I', t, t); execute format('create policy %I_self on %I for all to authenticated using ((select auth.uid()) = user_id) with check ((select auth.uid()) = user_id)', t, t); end loop; end $$;
create policy leaderboard_read on leaderboard_entries for select to authenticated using (true);
